prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?modelName ?modelId ?created WHERE {
  ?org a bboExt:Organization .
  ?org tai:organizationId "5e1278d2bfce434b95e80ab3625cdc63" .

  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:normalizedId ?modelId ;
         tai:modelCreated ?created ;
         tai:belongsTo ?org .

  ?participant a bboExt:Participant ;
               bbo:name ?pName ;
               tai:belongsTo ?choreo .

  FILTER(CONTAINS(LCASE(STR(?pName)), LCASE("Operatar")))
  ?participant tai:belongsTo ?choreo .
}
ORDER BY ?created
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?modelName ?modelId ?created ?pName ?choreo WHERE {
  ?org a bboExt:Organization .
  ?org tai:organizationId "5e1278d2bfce434b95e80ab3625cdc63" .

  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:normalizedId ?modelId ;
         tai:modelCreated ?created ;
         tai:belongsTo ?org .

  ?choreo tai:belongsTo ?model .
  ?participant a bboExt:Participant ;
               bbo:name ?pName ;
               tai:belongsTo ?choreo .

  FILTER(CONTAINS(LCASE(STR(?pName)), LCASE("operat")))
}
